static string BuildDefaultRepresentation(int input)
    {
        if (input == 0)
        {
            return input.ToString();
        }

        var absolute = Math.Abs((long)input);
        var nfi = LocaleNumberFormattingOverrides.GetFormattingNumberFormat(CultureInfo.CurrentCulture);

        if (absolute < 1_000)
        {
            return input.ToString(nfi);
        }

        if (absolute < 1_000_000)
        {
            return (input / 1_000d).ToString("G15", nfi) + "k";
        }

        if (absolute < 1_000_000_000)
        {
            return (input / 1_000_000d).ToString("G15", nfi) + "M";
        }

        return (input / 1_000_000_000d).ToString("G15", nfi) + "G";
    }

switch (Path.GetExtension(path))
            {
                case ".sh":
                    // use 'sh' args but prefer bash
                    if (WhichUtil.Which("bash", false, trace, prependPath) != null)
                    {
                        return "bash";
                    }
                    return "sh";
                case ".ps1":
                    if (WhichUtil.Which("pwsh", false, trace, prependPath) != null)
                    {
                        return "pwsh";
                    }
                    return "powershell";
                case ".js":
                    return Path.Combine(hostContext.GetDirectory(WellKnownDirectory.Externals), NodeUtil.GetInternalNodeVersion(), "bin", $"node{IOUtil.ExeExtension}") + " {0}";
                default:
                    throw new ArgumentException($"{path} is not a valid path to a script. Make sure it ends in '.sh', '.ps1' or '.js'.");
            }

while (true)
            {
                ConsoleKeyInfo key = Console.ReadKey(intercept: true);
                if (key.Key == ConsoleKey.Enter)
                {
                    Console.WriteLine();
                    break;
                }
                else if (key.Key == ConsoleKey.Backspace)
                {
                    if (chars.Count > 0)
                    {
                        chars.RemoveAt(chars.Count - 1);
                        Console.Write("\b \b");
                    }
                }
                else if (key.KeyChar > 0)
                {
                    chars.Add(key.KeyChar);
                    Console.Write("*");
                }
            }

if (checkGit.SslError)
            {
                await File.AppendAllLinesAsync(_logFile, new[] { $"{DateTime.UtcNow.ToString("O")} Try fix SSL error by providing extra CA certificate." });
                var downloadCert = await HostContext.DownloadExtraCA(url, pat);
                await File.AppendAllLinesAsync(_logFile, downloadCert.Logs);

                if (downloadCert.Pass)
                {
                    var recheckGit = await CheckGit(url, pat, extraCA: true);
                    await File.AppendAllLinesAsync(_logFile, recheckGit.Logs);
                    if (recheckGit.Pass)
                    {
                        await File.AppendAllLinesAsync(_logFile, new[] { $"{DateTime.UtcNow.ToString("O")} Fixed SSL error by providing extra CA certs." });
                    }
                }
            }

if (systemConnection?.Authorization != null &&
                systemConnection.Authorization.Parameters.TryGetValue("AccessToken", out var accessToken) &&
                !string.IsNullOrEmpty(accessToken))
            {
                var jwt = JsonWebToken.Create(accessToken);
                var claims = jwt.ExtractClaims();
                orchestrationId = claims.FirstOrDefault(x => string.Equals(x.Type, "orch_id", StringComparison.OrdinalIgnoreCase))?.Value;
                if (string.IsNullOrEmpty(orchestrationId))
                {
                    orchestrationId = claims.FirstOrDefault(x => string.Equals(x.Type, "orchid", StringComparison.OrdinalIgnoreCase))?.Value;
                }

                if (!string.IsNullOrEmpty(orchestrationId))
                {
                    Trace.Info($"Pull OrchestrationId {orchestrationId} from JWT claims");
                }
            }

if (string.IsNullOrEmpty(targetVersion))
            {
                var packages = await _runnerServer.GetPackagesAsync(_packageType, _platform, 1, true, token);
                if (packages == null || packages.Count == 0)
                {
                    Trace.Info($"There is no package for {_packageType} and {_platform}.");
                    return false;
                }

                _targetPackage = packages.FirstOrDefault();
            }
            else
            {
                _targetPackage = await _runnerServer.GetPackageAsync(_packageType, _platform, targetVersion, true, token);
                if (_targetPackage == null)
                {
                    Trace.Info($"There is no package for {_packageType} and {_platform} with version {targetVersion}.");
                    return false;
                }
            }

if (batch is IBatchContainerBatch)
            {
                var batchContainerBatch = batch as IBatchContainerBatch;
                await NextBatch(batchContainerBatch, streamProviderName, streamId, currentSubscriptionId);
            }
            else
            {
                if (this.observer != null)
                {
                    foreach (var itemTuple in batch.GetEvents<T>())
                    {
                        if (await NextItem(itemTuple.Item1, itemTuple.Item2))
                        {
                            EmitItemDelivered(streamProviderName, streamId, currentSubscriptionId, itemTuple.Item2);
                        }
                    }
                }
                else
                {
                    await NextItems(batch.GetEvents<T>(), streamProviderName, streamId, currentSubscriptionId);
                }
            }

try
            {
                task = queueGrain.Dequeue(maxCount);
                awaitingTasks.Add(task);
                var eventData = await task;
                batches = eventData.Select(data => new MemoryBatchContainer<TSerializer>(data, this.serializer)).ToList<IBatchContainer>();
                watch.Stop();
                this.receiverMonitor?.TrackRead(true, watch.Elapsed, null);
                if (eventData.Count > 0)
                {
                    var oldestMessage = eventData[0];
                    var newestMessage = eventData[eventData.Count - 1];
                    this.receiverMonitor?.TrackMessagesReceived(eventData.Count, oldestMessage.EnqueueTimeUtc, newestMessage.EnqueueTimeUtc);
                }
            }
            catch (Exception exc)
            {
                LogErrorGetQueueMessagesAsync(exc);
                watch.Stop();
                this.receiverMonitor?.TrackRead(true, watch.Elapsed, exc);
                throw;
            }
            finally
            {
                awaitingTasks.Remove(task);
            }

try
            {
                int numRemoved = State.Producers.RemoveWhere(s => s.Equals(streamId, streamProducer));
                LogPubSubCounts("UnregisterProducer {0} NumRemoved={1}", streamProducer, numRemoved);

                if (numRemoved > 0)
                {
                    Task updateStorageTask = State.Producers.Count == 0 && State.Consumers.Count == 0
                        ? ClearStateAsync() //State contains no producers or consumers, remove it from storage
                        : WriteStateAsync();
                    await updateStorageTask;
                    StreamingEvents.EmitProducerUnregistered(streamId.ProviderName, streamId.StreamId, streamProducer, GrainContext.Address.SiloAddress);
                }
                _streamInstruments.PubSubProducersTotal.Add(-numRemoved);
            }
            catch (Exception exc)
            {
                LogErrorUnregisterProducer(streamId, streamProducer, exc);

                // Corrupted state, deactivate grain.
                DeactivateOnIdle();
                throw;
            }

try
            {
                if (pubSubState == null)
                {
                    pubSubState = new PubSubSubscriptionState(subscriptionId, streamId, streamConsumer);
                    State.Consumers.Add(pubSubState);
                }

                if (!string.IsNullOrWhiteSpace(filterData))
                    pubSubState.AddFilter(filterData);

                LogPubSubCounts("RegisterConsumer {0}", streamConsumer);
                await WriteStateAsync();
                StreamingEvents.EmitSubscriptionRegistered(streamId.ProviderName, streamId.StreamId, subscriptionId.Guid, streamConsumer, GrainContext.Address.SiloAddress);
                _streamInstruments.PubSubConsumersTotal.Add(1);
            }
            catch (Exception exc)
            {
                LogErrorRegisterConsumer(streamId, subscriptionId, streamConsumer, exc);

                // Corrupted state, deactivate grain.
                DeactivateOnIdle();
                throw;
            }

if (streamConsumer != default)
            {
                List<StreamSubscription> subscriptions =
                    State.Consumers.Where(c => !c.IsFaulted && c.Consumer.Equals(streamConsumer))
                        .Select(
                            c =>
                                new StreamSubscription(c.SubscriptionId.Guid, streamId.ProviderName, streamId,
                                    streamConsumer)).ToList();
                return Task.FromResult(subscriptions);
            }
            else
            {
                List<StreamSubscription> subscriptions =
                    State.Consumers.Where(c => !c.IsFaulted)
                        .Select(
                            c =>
                                new StreamSubscription(c.SubscriptionId.Guid, streamId.ProviderName, streamId,
                                    c.Consumer)).ToList();
                return Task.FromResult(subscriptions);
            }

if (silosToStart > 0)
        {
            var siloStartTasks = Enumerable.Range(_startedInstances, silosToStart)
                .Select(instanceNumber => Task.Run(() => StartSiloAsync((short)instanceNumber, Options))).ToArray();

            try
            {
                await Task.WhenAll(siloStartTasks);
            }
            catch (Exception)
            {
                lock (_silos)
                {
                    _silos.AddRange(siloStartTasks.Where(t => t.Exception == null).Select(t => t.Result));
                }

                throw;
            }

            instances.AddRange(siloStartTasks.Select(t => t.Result));
            lock (_silos)
            {
                _silos.AddRange(instances);
            }
        }

try
                {
                    Process.BeginOutputReadLine();
                    Process.BeginErrorReadLine();

                    var waitForExit = Task.Factory.StartNew(
                        process => ((Process)process).WaitForExit(-1),
                        Process,
                        CancellationToken.None,
                        TaskCreationOptions.LongRunning | TaskCreationOptions.RunContinuationsAsynchronously,
                        TaskScheduler.Default);
                    await Task.WhenAll(waitForExit, _outputCloseEvent.Task, _errorCloseEvent.Task);

                    if (!await waitForExit)
                    {
                        try
                        {
                            Process.Kill();
                        }
                        catch
                        {
                        }
                    }
                }
                catch (Exception exception)
                {
                    _startedEvent.TrySetException(exception);
                }

try
            {
                if (ct.IsCancellationRequested)
                {
                    this.Process?.Kill();
                }
                else
                {
                    using var registration = ct.Register(() =>
                    {
                        var process = this.Process;
                        if (process is not null)
                        {
                            process.Kill();
                        }
                    });

                    await this.Process.StandardInput.WriteLineAsync(StandaloneSiloHost.ShutdownCommand);
                    using var linkedCts = new CancellationTokenSource();
                    await Task.WhenAny(_runTask, Task.Delay(TimeSpan.FromMinutes(2), linkedCts.Token));
                }
            }
            finally
            {
                this.isActive = false;
            }

if (status != TransactionalStatus.Ok)
            {
                try
                {
                    LogDebugCommitTransactionFailure(new(stopwatch), transactionInfo.TransactionId, status);

                    // notify participants
                    if (status.DefinitelyAborted())
                    {
                        await Task.WhenAll(writeResources
                            .Where(p => !p.Equals(manager.Key))
                            .Select(p => p.Reference.AsReference<ITransactionalResourceExtension>()
                                    .Cancel(p.Name, transactionInfo.TransactionId, transactionInfo.TimeStamp, status)));
                    }
                }
                catch (Exception ex)
                {
                    LogDebugCommitReadWriteFailureAborting(new(stopwatch), transactionInfo.TransactionId, ex);
                    LogWarnFailAbortTransaction(transactionInfo.TransactionId, ex);
                }
            }

try
            {
                // Get a list of all processes
                snapshotHandle = Interop.Kernel32.CreateToolhelp32Snapshot(Interop.Kernel32.SnapshotFlags.Process, 0);

                Interop.Kernel32.PROCESSENTRY32 procEntry = default;
                procEntry.dwSize = sizeof(Interop.Kernel32.PROCESSENTRY32);
                if (Interop.Kernel32.Process32First(snapshotHandle, &procEntry))
                {
                    int currentProcessId = Environment.ProcessId;
                    do
                    {
                        if (currentProcessId == procEntry.th32ProcessID)
                        {
                            return Process.GetProcessById(procEntry.th32ParentProcessID);
                        }
                    }
                    while (Interop.Kernel32.Process32Next(snapshotHandle, &procEntry));
                }
            }
            catch (Exception)
            {
            }
            finally
            {
                Interop.Kernel32.CloseHandle(snapshotHandle);
            }

if (values != null && values.Length != 0 && format != null)
            {
                if (s_count >= MaxCachedFormatters)
                {
                    if (!s_formatters.TryGetValue(format, out _formatter))
                    {
                        _formatter = new LogValuesFormatter(format);
                    }
                }
                else
                {
                    _formatter = s_formatters.GetOrAdd(format, f =>
                    {
                        Interlocked.Increment(ref s_count);
                        return new LogValuesFormatter(f);
                    });
                }
            }
            else
            {
                _formatter = null;
            }

if (exitCode == 0)
            {
                // remove any empty line.
                outputStrings = outputStrings.Where(o => !string.IsNullOrEmpty(o)).ToList();
                if (outputStrings.Count == 1 && !string.IsNullOrEmpty(outputStrings.First()))
                {
                    string verString = outputStrings.First();
                    // we interested about major.minor.patch version
                    Regex verRegex = new("\\d+\\.\\d+(\\.\\d+)?", RegexOptions.IgnoreCase);
                    var matchResult = verRegex.Match(verString);
                    if (matchResult.Success && !string.IsNullOrEmpty(matchResult.Value))
                    {
                        if (!Version.TryParse(matchResult.Value, out version))
                        {
                            version = null;
                        }
                    }
                }
            }

if ((_proc.StartInfo.RedirectStandardError || _proc.StartInfo.RedirectStandardOutput) && _asyncStreamReaderCount != 0)
            {
                _waitingOnStreams = true;

                Task.Run(async () =>
                {
                    // Wait 5 seconds and then Cancel/Kill process tree
                    await Task.Delay(TimeSpan.FromSeconds(5));
                    KillProcessTree();
                    _processExitedCompletionSource.TrySetResult(true);
                    _processStandardInWriteCancellationTokenSource.Cancel();
                });
            }
            else
            {
                _processExitedCompletionSource.TrySetResult(true);
                _processStandardInWriteCancellationTokenSource.Cancel();
            }

while (!_processExitedCompletionSource.Task.IsCompleted)
                {
                    ValueTask<string> dequeueTask = redirectStandardIn.Reader.ReadAsync(_processStandardInWriteCancellationTokenSource.Token);
                    string input = await dequeueTask;
                    if (input != null)
                    {
                        utf8Writer.WriteLine(input);
                        utf8Writer.Flush();

                        if (!keepStandardInOpen)
                        {
                            Trace.Info("Close STDIN after the first redirect finished.");
                            standardIn.Close();
                            break;
                        }
                    }
                }

if (rootStepId == default(Guid))
            {
                IOUtil.DeleteDirectory(HostContext.GetDirectory(WellKnownDirectory.Actions), executionContext.CancellationToken);
            }
            // We are running mid job due to a local composite action
            else
            {
                if (!_cachedEmbeddedStepIds.ContainsKey(rootStepId))
                {
                    _cachedEmbeddedStepIds[rootStepId] = new List<Guid>();
                    foreach (var compositeStep in steps)
                    {
                        var guid = Guid.NewGuid();
                        compositeStep.Id = guid;
                        _cachedEmbeddedStepIds[rootStepId].Add(guid);
                    }
                }
                depth = 1;
            }

while (retryCount < 3)
            {
                buildExitCode = await dockerManager.DockerBuild(
                    executionContext,
                    setupInfo.Container.WorkingDirectory,
                    setupInfo.Container.Dockerfile,
                    Directory.GetParent(setupInfo.Container.Dockerfile).FullName,
                    imageName);
                if (buildExitCode == 0)
                {
                    break;
                }
                else
                {
                    retryCount++;
                    if (retryCount < 3)
                    {
                        var backOff = BackoffTimerHelper.GetRandomBackoff(TimeSpan.FromSeconds(1), TimeSpan.FromSeconds(10));
                        executionContext.Warning($"Docker build failed with exit code {buildExitCode}, back off {backOff.TotalSeconds} seconds before retry.");
                        await Task.Delay(backOff);
                    }
                }
            }

if (executionContext.Global.Variables.GetBoolean(Constants.Runner.Features.UseBearerTokenForCodeload) == true &&
                Uri.TryCreate(downloadUrl, UriKind.Absolute, out var parsedUrl) &&
                !string.IsNullOrEmpty(parsedUrl?.Host) &&
                !string.IsNullOrEmpty(parsedUrl?.PathAndQuery) &&
                (parsedUrl.Host.StartsWith("codeload.", StringComparison.OrdinalIgnoreCase) || parsedUrl.PathAndQuery.StartsWith("/_codeload/", StringComparison.OrdinalIgnoreCase)))
            {
                Trace.Info("Using Bearer token for action archive download directly to codeload.");
                return new AuthenticationHeaderValue("Bearer", token);
            }
            else
            {
                Trace.Info("Using Basic token for action archive download.");
                var base64EncodingToken = Convert.ToBase64String(Encoding.UTF8.GetBytes($"x-access-token:{token}"));
                HostContext.SecretMasker.AddValue(base64EncodingToken);
                return new AuthenticationHeaderValue("Basic", base64EncodingToken);
            }

while (retryCount < 3)
            {
                loginExitCode = await _dockerManager.DockerLogin(
                    executionContext,
                    configLocation,
                    container.RegistryServer,
                    container.RegistryAuthUsername,
                    container.RegistryAuthPassword);
                if (loginExitCode == 0)
                {
                    break;
                }
                else
                {
                    retryCount++;
                    if (retryCount < 3)
                    {
                        var backOff = BackoffTimerHelper.GetRandomBackoff(TimeSpan.FromSeconds(1), TimeSpan.FromSeconds(10));
                        executionContext.Warning($"Docker login for '{container.RegistryServer}' failed with exit code {loginExitCode}, back off {backOff.TotalSeconds} seconds before retry.");
                        await Task.Delay(backOff);
                    }
                }
            }

try
            {
                var result = step.ExecutionContext?.Result;
                Trace.Info("Step completed");

                // Add to completed steps list for stack trace
                lock (_stateLock)
                {
                    if (_state != DapSessionState.Ready &&
                        _state != DapSessionState.Paused &&
                        _state != DapSessionState.Running)
                    {
                        return;
                    }

                    _completedSteps.Add(new CompletedStepInfo
                    {
                        DisplayName = step.DisplayName,
                        Result = result,
                        FrameId = _nextCompletedFrameId++,
                        SourceLine = _jobStepsSource?.TryGetLineForStep(step)
                    });
                }
            }
            catch (Exception ex)
            {
                Trace.Warning($"DAP OnStepCompleted error: {ex.Message}");
            }

while (true)
            {
                var line = await ReadLineAsync(cancellationToken);
                if (line == null)
                {
                    return null;
                }

                if (line.Length == 0)
                {
                    break;
                }

                if (line.StartsWith(_contentLengthHeader, StringComparison.OrdinalIgnoreCase))
                {
                    var lengthStr = line.Substring(_contentLengthHeader.Length).Trim();
                    if (!int.TryParse(lengthStr, out contentLength))
                    {
                        throw new InvalidDataException($"Invalid Content-Length: {lengthStr}");
                    }
                }
            }

while (true)
            {
                var bytesRead = await _stream.ReadAsync(buffer, 0, 1, cancellationToken);
                if (bytesRead == 0)
                {
                    return lineBuilder.Length > 0 ? lineBuilder.ToString() : null;
                }

                var c = (char)buffer[0];

                if (c == '\n' && previousWasCr)
                {
                    if (lineBuilder.Length > 0 && lineBuilder[lineBuilder.Length - 1] == '\r')
                    {
                        lineBuilder.Length--;
                    }
                    return lineBuilder.ToString();
                }

                previousWasCr = c == '\r';
                lineBuilder.Append(c);

                if (lineBuilder.Length > _maxHeaderLineLength)
                {
                    throw new InvalidDataException($"Header line exceeds maximum length of {_maxHeaderLineLength}");
                }
            }

try
            {
                _sendLock.Wait();
                try
                {
                    if (_stream == null)
                    {
                        Trace.Warning("Cannot send message: no client connected");
                        return;
                    }

                    message.Seq = _nextSeq++;
                    SendMessageInternal(message);
                }
                finally
                {
                    _sendLock.Release();
                }

                Trace.Info("Sent message");
            }
            catch (Exception ex)
            {
                Trace.Warning($"Failed to send message ({ex.GetType().Name})");
            }

for (int i = 1; i < input.Length; i++)
            {
                if (input[i] == '\\' && i + 1 < input.Length)
                {
                    sb.Append(input[i + 1]);
                    i++;
                }
                else if (input[i] == '"')
                {
                    // Check nothing meaningful follows the closing quote
                    var rest = input.Substring(i + 1).Trim();
                    if (rest.Length > 0)
                    {
                        error = $"Unexpected content after closing quote: {Truncate(rest, 40)}";
                        return null;
                    }
                    return sb.ToString();
                }
                else
                {
                    sb.Append(input[i]);
                }
            }

if (variablesReference >= _scopeReferenceBase && variablesReference <= _scopeReferenceMax)
            {
                var scopeIndex = variablesReference - _scopeReferenceBase;
                if (scopeIndex < _scopeNames.Length)
                {
                    var scopeName = _scopeNames[scopeIndex];
                    isSecretsScope = scopeName == "secrets";
                    if (context.ExpressionValues.TryGetValue(scopeName, out data))
                    {
                        basePath = scopeName;
                    }
                }
            }
            else if (_variableReferences.TryGetValue(variablesReference, out var refData))
            {
                data = refData.Data;
                basePath = refData.Path;
                isSecretsScope = basePath?.StartsWith("secrets", StringComparison.OrdinalIgnoreCase) == true;
            }
